DateTime? _resolveTripHistoryReferenceAtUtc(Map<String, dynamic> tripData) {
  return _parseTripHistoryDate(tripData['endedAt']) ??
      _parseTripHistoryDate(tripData['updatedAt']) ??
      _parseTripHistoryDate(tripData['startedAt']);
}

DateTime? _parseTripHistoryDate(Object? raw) {
  if (raw is Timestamp) {
    return raw.toDate().toUtc();
  }
  if (raw is String) {
    final normalized = raw.trim();
    if (normalized.isEmpty) {
      return null;
    }
    return DateTime.tryParse(normalized)?.toUtc();
  }
  return null;
}

