String _formatTripCompletedClock(DateTime dateTimeUtc) {
  final local = dateTimeUtc.toLocal();
  final hour = local.hour.toString().padLeft(2, '0');
  final minute = local.minute.toString().padLeft(2, '0');
  return '$hour:$minute';
}
